package store

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"strconv"
	"strings"
	"time"

	"github.com/volcano-sh/agentcube/pkg/common/types"

	"github.com/valkey-io/valkey-go"
)

type valkeyStore struct {
	cli                 valkey.Client
	sessionPrefix       string
	expiryIndexKey      string
	lastActivityIndexKey string
}

func newValkeyStore() (Store, error) {
	addr := os.Getenv("VALKEY_ADDR")
	if addr == "" {
		addr = "localhost:6379"
	}

	password := ""
	passwordRequired := os.Getenv("VALKEY_PASSWORD_REQUIRED")
	if passwordRequired == "true" || passwordRequired == "" {
		password = os.Getenv("VALKEY_PASSWORD")
	}

	disableCache := os.Getenv("VALKEY_DISABLE_CACHE") == "true"
	forceSingle := os.Getenv("VALKEY_FORCE_SINGLE") == "true"

	opts, err := makeValkeyOptions(addr, password, disableCache, forceSingle)
	if err != nil {
		return nil, err
	}

	cli, err := valkey.NewClient(opts)
	if err != nil {
		return nil, err
	}

	return &valkeyStore{
		cli:                 cli,
		sessionPrefix:       sessionPrefix,
		expiryIndexKey:      expiryIndexKey,
		lastActivityIndexKey: lastActivityIndexKey,
	}, nil
}

func makeValkeyOptions(addr, password string, disableCache, forceSingle bool) (valkey.ClientOption, error) {
	addresses := strings.Split(addr, ",")

	initAddress := addresses
	if len(addresses) == 1 {
		initAddress = []string{addresses[0]}
	}

	opts := valkey.ClientOption{
		InitAddress:  initAddress,
		Password:     password,
		DisableCache: disableCache,
	}

	if forceSingle || len(addresses) == 1 {
		opts.AlwaysRESP2 = true
	}

	return opts, nil
}

func (v *valkeyStore) Ping(ctx context.Context) error {
	return v.cli.Do(ctx, v.cli.B().Ping().Build()).Error()
}

func (v *valkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := v.sessionPrefix + sessionID
	result, err := v.cli.Do(ctx, v.cli.B().Get().Key(key).Build()).AsBytes()
	if err != nil {
		if isValkeyNotFound(err) {
			return nil, ErrNotFound
		}
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal(result, &sandbox); err != nil {
		return nil, err
	}

	return &sandbox, nil
}

func (v *valkeyStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	key := v.sessionPrefix + sandbox.SessionID

	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	expiresAt := sandbox.ExpiresAt
	if expiresAt.IsZero() {
		expiresAt = time.Now().Add(8 * time.Hour)
	}

	ttl := int64(time.Until(expiresAt).Seconds())
	if ttl <= 0 {
		ttl = int64((8 * time.Hour).Seconds())
	}

	expiryScore := float64(expiresAt.Unix())
	lastActivity := sandbox.CreatedAt
	if sandbox.LastActivity != nil {
		lastActivity = *sandbox.LastActivity
	}
	lastActivityScore := float64(lastActivity.Unix())

	commands := []valkey.Completed{
		v.cli.B().Set().Key(key).Value(string(data)).Nx().Ex(ttl).Build(),
		v.cli.B().Zadd().Key(v.expiryIndexKey).ScoreMember().ScoreMember(expiryScore, sandbox.SessionID).Build(),
		v.cli.B().Zadd().Key(v.lastActivityIndexKey).ScoreMember().ScoreMember(lastActivityScore, sandbox.SessionID).Build(),
	}

	results := v.cli.DoMulti(ctx, commands...)
	for i, res := range results {
		if err := res.Error(); err != nil {
			return err
		}
		if i == 0 {
			val, _ := res.AsInt64()
			if val == 0 {
				return fmt.Errorf("sandbox already exists for session %s", sandbox.SessionID)
			}
		}
	}

	return nil
}

func (v *valkeyStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	key := v.sessionPrefix + sandbox.SessionID

	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	expiresAt := sandbox.ExpiresAt
	if expiresAt.IsZero() {
		expiresAt = time.Now().Add(8 * time.Hour)
	}

	ttl := int64(time.Until(expiresAt).Seconds())
	if ttl <= 0 {
		ttl = int64((8 * time.Hour).Seconds())
	}

	expiryScore := float64(expiresAt.Unix())
	lastActivity := sandbox.CreatedAt
	if sandbox.LastActivity != nil {
		lastActivity = *sandbox.LastActivity
	}
	lastActivityScore := float64(lastActivity.Unix())

	commands := []valkey.Completed{
		v.cli.B().Set().Key(key).Value(string(data)).Xx().Ex(ttl).Build(),
		v.cli.B().Zadd().Key(v.expiryIndexKey).ScoreMember().ScoreMember(expiryScore, sandbox.SessionID).Build(),
		v.cli.B().Zadd().Key(v.lastActivityIndexKey).ScoreMember().ScoreMember(lastActivityScore, sandbox.SessionID).Build(),
	}

	results := v.cli.DoMulti(ctx, commands...)
	if err := results[0].Error(); err != nil {
		return err
	}

	val, err := results[0].ToString()
	if err != nil || val != "OK" {
		return ErrNotFound
	}

	return nil
}

func (v *valkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	commands := []valkey.Completed{
		v.cli.B().Del().Key(v.sessionPrefix + sessionID).Build(),
		v.cli.B().Zrem().Key(v.expiryIndexKey).Member(sessionID).Build(),
		v.cli.B().Zrem().Key(v.lastActivityIndexKey).Member(sessionID).Build(),
	}

	results := v.cli.DoMulti(ctx, commands...)
	for _, res := range results {
		if err := res.Error(); err != nil {
			return err
		}
	}

	return nil
}

func (v *valkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	sessionIDs, err := v.getZSetByScore(ctx, v.expiryIndexKey, "-inf", before.Unix(), limit)
	if err != nil {
		return nil, err
	}

	return v.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (v *valkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	sessionIDs, err := v.getZSetByScore(ctx, v.lastActivityIndexKey, "-inf", before.Unix(), limit)
	if err != nil {
		return nil, err
	}

	return v.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (v *valkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	key := v.sessionPrefix + sessionID

	exists, err := v.cli.Do(ctx, v.cli.B().Exists().Key(key).Build()).AsInt64()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	cmd := v.cli.B().Zadd().Key(v.lastActivityIndexKey).ScoreMember().ScoreMember(float64(at.Unix()), sessionID).Build()
	return v.cli.Do(ctx, cmd).Error()
}

func (v *valkeyStore) Close() error {
	v.cli.Close()
	return nil
}

func (v *valkeyStore) getZSetByScore(ctx context.Context, key string, min string, max int64, limit int64) ([]string, error) {
	cmd := v.cli.B().Zrangebyscore().Key(key).Min(valkey.Min(min)).Max(valkey.Max(strconv.FormatInt(max, 10))).Limit(0, limit).Build()
	result, err := v.cli.Do(ctx, cmd).AsStrSlice()
	if err != nil {
		return nil, err
	}
	return result, nil
}

func (v *valkeyStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return []*types.SandboxInfo{}, nil
	}

	commands := make([]valkey.Completed, len(sessionIDs))
	for i, id := range sessionIDs {
		commands[i] = v.cli.B().Get().Key(v.sessionPrefix + id).Build()
	}

	results := v.cli.DoMulti(ctx, commands...)

	var result []*types.SandboxInfo
	for _, res := range results {
		data, err := res.AsBytes()
		if err != nil {
			if isValkeyNotFound(err) {
				continue
			}
			return nil, err
		}

		var sandbox types.SandboxInfo
		if err := json.Unmarshal(data, &sandbox); err != nil {
			continue
		}
		result = append(result, &sandbox)
	}

	return result, nil
}

func isValkeyNotFound(err error) bool {
	if err == nil {
		return false
	}
	return strings.Contains(err.Error(), "nil") || strings.Contains(err.Error(), "no such key")
}

