package store

import (
	"os"
	"sync"
)

const (
	redisStoreType  = "redis"
	valkeyStoreType = "valkey"
)

var (
	initStoreOnce *sync.Once = &sync.Once{}
	provider      Store
)

func Storage() Store {
	initStoreOnce.Do(func() {
		if err := initStore(); err != nil {
			panic(err)
		}
	})
	return provider
}

func initStore() error {
	storeType := os.Getenv("STORE_TYPE")
	if storeType == "" {
		storeType = redisStoreType
	}

	switch storeType {
	case redisStoreType:
		p, err := newRedisStore()
		if err != nil {
			return err
		}
		provider = p
	case valkeyStoreType:
		p, err := newValkeyStore()
		if err != nil {
			return err
		}
		provider = p
	default:
		panic("unknown store type: " + storeType)
	}

	return nil
}

