	key := r.sessionPrefix + sessionID
	data, err := r.cli.Get(ctx, key).Bytes()
	if err == redisv9.Nil {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal(data, &sandbox); err != nil {
		return nil, err
	}

	return &sandbox, nil
}

func (r *redisStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	key := r.sessionPrefix + sandbox.SessionID

	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	expiresAt := sandbox.ExpiresAt
	if expiresAt.IsZero() {
		expiresAt = time.Now().Add(8 * time.Hour)
	}

	ttl := time.Until(expiresAt)
	if ttl <= 0 {
		ttl = 8 * time.Hour
	}

	pipe := r.cli.Pipeline()

	setCmd := pipe.SetNX(ctx, key, data, ttl)

	expiryScore := float64(expiresAt.Unix())
	pipe.ZAdd(ctx, r.expiryIndexKey, redisv9.Z{
		Score:  expiryScore,
		Member: sandbox.SessionID,
	})

	lastActivity := sandbox.CreatedAt
	if sandbox.LastActivity != nil {
		lastActivity = *sandbox.LastActivity
	}
	pipe.ZAdd(ctx, r.lastActivityIndexKey, redisv9.Z{
		Score:  float64(lastActivity.Unix()),
		Member: sandbox.SessionID,
	})

	_, err = pipe.Exec(ctx)
	if err != nil {
		return err
	}

	if !setCmd.Val() {
		return fmt.Errorf("sandbox already exists for session %s", sandbox.SessionID)
	}

	return nil
}

