	if err != nil {
		return nil, err
	}

	return r.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (r *redisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	key := r.sessionPrefix + sessionID

	exists, err := r.cli.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	pipe := r.cli.Pipeline()
	pipe.ZAdd(ctx, r.lastActivityIndexKey, redisv9.Z{
		Score:  float64(at.Unix()),
		Member: sessionID,
	})
	_, err = pipe.Exec(ctx)
	return err
}

func (r *redisStore) Close() error {
	return r.cli.Close()
}

func (r *redisStore) getZSetByScore(ctx context.Context, key string, min string, max int64, limit int64) ([]string, error) {
	result, err := r.cli.ZRangeByScore(ctx, key, &redisv9.ZRangeBy{
		Min:    min,
		Max:    fmt.Sprintf("%d", max),
		Offset: 0,
		Count:  limit,
	}).Result()
	if err != nil {
		return nil, err
	}
	return result, nil
}

func (r *redisStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return []*types.SandboxInfo{}, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = r.sessionPrefix + id
	}

	pipe := r.cli.Pipeline()
	cmds := make([]*redisv9.BytesCmd, len(keys))
	for i, key := range keys {
		cmds[i] = pipe.Get(ctx, key)
	}

	_, err := pipe.Exec(ctx)
	if err != nil && err != redisv9.Nil {
		return nil, err
	}

	var result []*types.SandboxInfo
	for _, cmd := range cmds {
		data, err := cmd.Result()
		if err == redisv9.Nil {
			continue
		}
		if err != nil {
			return nil, err
		}

		var sandbox types.SandboxInfo
		if err := json.Unmarshal(data, &sandbox); err != nil {
			continue
		}
		result = append(result, &sandbox)
	}

	return result, nil
}

