package workloadmanager

import (
	"context"
	"sync"
	"time"

	authenticationv1 "k8s.io/api/authentication/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
)

type TokenCache struct {
	cache    map[string]cacheEntry
	mu       sync.RWMutex
	capacity int
	ttl      time.Duration
}

type cacheEntry struct {
	username  string
	saName    string
	namespace string
	expiresAt time.Time
}

func NewTokenCache(capacity int, ttl time.Duration) *TokenCache {
	return &TokenCache{
		cache:    make(map[string]cacheEntry),
		capacity: capacity,
		ttl:      ttl,
	}
}

func (tc *TokenCache) Get(key string) (username, saName, namespace string, ok bool) {
	tc.mu.RLock()
	defer tc.mu.RUnlock()

	entry, exists := tc.cache[key]
	if !exists || time.Now().After(entry.expiresAt) {
		return "", "", "", false
	}

	return entry.username, entry.saName, entry.namespace, true
}

func (tc *TokenCache) Set(key, username, saName, namespace string) {
	tc.mu.Lock()
	defer tc.mu.Unlock()

	if len(tc.cache) >= tc.capacity {
		tc.evictExpired()
	}

	tc.cache[key] = cacheEntry{
		username:  username,
		saName:    saName,
		namespace: namespace,
		expiresAt: time.Now().Add(tc.ttl),
	}
}

func (tc *TokenCache) evictExpired() {
	now := time.Now()
	for key, entry := range tc.cache {
		if now.After(entry.expiresAt) {
			delete(tc.cache, key)
		}
	}
}

func (tc *TokenCache) validateServiceAccountToken(ctx context.Context, clientset *kubernetes.Clientset, token, namespace string) (username, saName, ns string, err error) {
	tokenReview := &authenticationv1.TokenReview{
		Spec: authenticationv1.TokenReviewSpec{
			Token: token,
		},
	}

	result, err := clientset.AuthenticationV1().TokenReviews().Create(ctx, tokenReview, metav1.CreateOptions{})
	if err != nil {
		return "", "", "", err
	}

	if !result.Status.Authenticated {
		return "", "", "", ErrUnauthorized
	}

	saName = result.Status.User.Username
	if colonIdx := len("system:serviceaccount:"); len(saName) > colonIdx {
		parts := saName[colonIdx:]
		if slashIdx := indexRune(parts, ':'); slashIdx != -1 {
			ns = parts[:slashIdx]
			saName = parts[slashIdx+1:]
		}
	}

	tc.Set(token, result.Status.User.Username, saName, namespace)

	return result.Status.User.Username, saName, namespace, nil
}

func indexRune(s string, r rune) int {
	for i, c := range s {
		if c == r {
			return i
		}
	}
	return -1
}

var ErrUnauthorized = &unauthorizedError{}

type unauthorizedError struct{}

func (e *unauthorizedError) Error() string   { return "unauthorized" }
func (e *unauthorizedError) Unauthorized() bool { return true }

